import AppKit

/// Menu bar dolphin, embedded as a base64 template PNG (black art + alpha).
/// Marked as a template image so the menu bar tints it for light/dark.
enum DolphinAsset {
    static let image: NSImage = {
        let data = Data(base64Encoded: base64)!
        let img = NSImage(data: data) ?? NSImage()
        img.isTemplate = true
        return img
    }()

    private static let base64 = """

"""
}